INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "ミッションをクリアして、\n報酬をゲットしましょう！", "カリン", 3.099, 10057, 190804, 2, -416.5, "2021/01/15 12:00:00", 53, "2021/01/24 14:59:59", 1, 2, 10057002);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "受け取ることができる\n報酬があるようです\n確認してみてください", "カリン", 2.801, 10057, 190804, 3, -416.5, "2021/01/15 12:00:00", 54, "2021/01/24 14:59:59", 1, 2, 10057003);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "報酬がもらえますよ！\nチェックしてみてください", "カリン", 0.0, 10057, 190804, 4, -416.5, "2021/01/15 12:00:00", 54, "2021/01/24 14:59:59", 2, 2, 10057004);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", "カリン", 0.0, 10057, 190804, 5, -416.5, "2021/01/15 12:00:00", 57, "2021/01/24 14:59:59", 1, 1, 10057005);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", "カリン", 5.506, 10057, 190804, 1, -363.0, "2021/01/15 12:00:00", 55, "2021/01/24 14:59:59", 1, 2, 10057006);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "お疲れ様です！\nここでは、討伐証と報酬を\n交換することができます！", "カリン", 1.216, 10057, 190804, 2, -363.0, "2021/01/15 12:00:00", 55, "2021/01/24 14:59:59", 2, 1, 10057007);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "お疲れ様でした\n討伐証の交換、\nお忘れないように！", "カリン", 1.539, 10057, 190804, 3, -363.0, "2021/01/15 12:00:00", 56, "2021/01/24 14:59:59", 2, 1, 10057008);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "終わっちゃいましたねー\n討伐証は努力の証！\n報酬と交換しましょう！", "カリン", 1.875, 10057, 190804, 4, -363.0, "2021/01/15 12:00:00", 56, "2021/01/24 14:59:59", 2, 1, 10057009);
