INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", "カリン", 3.414, 10113, 190801, 1, -416.5, "2023/02/14 12:00:00", 53, "2023/02/26 14:59:59", 1, 2, 10113001);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "ミッションをクリアして、\n報酬をゲットしましょう！", "カリン", 3.099, 10113, 190801, 2, -416.5, "2023/02/14 12:00:00", 53, "2023/02/26 14:59:59", 1, 2, 10113002);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "受け取ることができる\n報酬があるようです\n確認してみてください", "カリン", 2.801, 10113, 190801, 3, -416.5, "2023/02/14 12:00:00", 54, "2023/02/26 14:59:59", 1, 2, 10113003);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "報酬がもらえますよ！\nチェックしてみてください", "カリン", 0.0, 10113, 190801, 4, -416.5, "2023/02/14 12:00:00", 54, "2023/02/26 14:59:59", 2, 2, 10113004);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", "カリン", 0.0, 10113, 190801, 5, -416.5, "2023/02/14 12:00:00", 57, "2023/02/26 14:59:59", 1, 1, 10113005);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", "カリン", 5.506, 10113, 190801, 1, -363.0, "2023/02/14 12:00:00", 55, "2023/02/26 14:59:59", 1, 2, 10113006);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "お疲れ様です！\nここでは、討伐証と報酬を\n交換することができます！", "カリン", 1.216, 10113, 190801, 2, -363.0, "2023/02/14 12:00:00", 55, "2023/02/26 14:59:59", 2, 1, 10113007);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "お疲れ様でした\n討伐証の交換、\nお忘れないように！", "カリン", 1.539, 10113, 190801, 3, -363.0, "2023/02/14 12:00:00", 56, "2023/02/26 14:59:59", 2, 1, 10113008);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "終わっちゃいましたねー\n討伐証は努力の証！\n報酬と交換しましょう！", "カリン", 1.875, 10113, 190801, 4, -363.0, "2023/02/14 12:00:00", 56, "2023/02/26 14:59:59", 2, 1, 10113009);
