INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "ミッションをクリアして、\n報酬をゲットしましょう！", "カリン", 3.099, 20025, 190801, 2, -416.5, "2022/03/17 15:00:00", 53, "2030/01/01 14:59:59", 1, 2, 20025002);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "受け取ることができる\n報酬があるようです\n確認してみてください", "カリン", 2.801, 20025, 190801, 3, -416.5, "2022/03/17 15:00:00", 54, "2030/01/01 14:59:59", 1, 2, 20025003);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "報酬がもらえますよ！\nチェックしてみてください", "カリン", 0.0, 20025, 190801, 4, -416.5, "2022/03/17 15:00:00", 54, "2030/01/01 14:59:59", 2, 2, 20025004);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", "カリン", 0.0, 20025, 190801, 5, -416.5, "2022/03/17 15:00:00", 57, "2030/01/01 14:59:59", 1, 1, 20025005);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", "カリン", 5.506, 20025, 190801, 1, -363.0, "2022/03/17 15:00:00", 55, "2030/01/01 14:59:59", 1, 2, 20025006);
